/**
 * UserProfile - Shell profile page for account details and stored preferences.
 * Centralizes preference management that was previously exposed in feature views.
 */
import React, { useEffect, useMemo, useState } from 'react';
import Box from '@mui/material/Box';
import Typography from '@mui/material/Typography';
import { useAuth } from '@shared/auth';
import { Button, Card, PageHeader, UserPreferencesPanel } from '@shared/ui-components';

// Generated by GitHub Copilot
const PREFS_STORAGE_PREFIX = 'partner-portal:prefs:';

interface PreferenceSummary {
    view: string;
    namespace: string;
    recordCount: number | null;
}

/**
 * Computes per-view preference summaries from localStorage.
 */
function readPreferenceSummaries(): PreferenceSummary[] {
    const summaries: PreferenceSummary[] = [];

    for (let index = 0; index < localStorage.length; index += 1) {
        const key = localStorage.key(index);
        if (!key || !key.startsWith(PREFS_STORAGE_PREFIX)) {
            continue;
        }

        const namespace = key.slice(PREFS_STORAGE_PREFIX.length);
        const view = namespace.split('.')[0] ?? namespace;
        const rawValue = localStorage.getItem(key);

        let recordCount: number | null = null;
        if (rawValue) {
            try {
                const parsed = JSON.parse(rawValue);
                if (Array.isArray(parsed)) {
                    recordCount = parsed.length;
                } else if (parsed && typeof parsed === 'object') {
                    recordCount = Object.keys(parsed as Record<string, unknown>).length;
                }
            } catch {
                recordCount = null;
            }
        }

        summaries.push({ view, namespace, recordCount });
    }

    return summaries.sort((a, b) => a.namespace.localeCompare(b.namespace));
}

const UserProfile: React.FC = () => {
    const { user } = useAuth();
    const [preferencesOpen, setPreferencesOpen] = useState(false);
    const [summaries, setSummaries] = useState<PreferenceSummary[]>([]);

    useEffect(() => {
        setSummaries(readPreferenceSummaries());
    }, [preferencesOpen]);

    const groupedSummaries = useMemo(() => {
        const grouped = new Map<string, PreferenceSummary[]>();

        for (const summary of summaries) {
            const existing = grouped.get(summary.view) ?? [];
            grouped.set(summary.view, [...existing, summary]);
        }

        return Array.from(grouped.entries()).sort(([left], [right]) => left.localeCompare(right));
    }, [summaries]);

    return (
        <section aria-label="User Profile">
            <PageHeader
                title="User Profile"
                subtitle="Manage account details and saved preferences across all views"
                actions={
                    <Button onClick={() => setPreferencesOpen(true)}>
                        Open Preferences Manager
                    </Button>
                }
            />

            <Box sx={{ display: 'grid', gridTemplateColumns: { xs: '1fr', lg: '1fr 2fr' }, gap: 2 }}>
                <Card title="Account">
                    <Box sx={{ display: 'grid', gap: 1 }}>
                        <Typography variant="body2" color="text.secondary">Name</Typography>
                        <Typography variant="body1" fontWeight={600}>{user?.displayName ?? 'Guest'}</Typography>
                        <Typography variant="body2" color="text.secondary">Email</Typography>
                        <Typography variant="body1">{user?.email ?? 'Not signed in'}</Typography>
                        <Typography variant="body2" color="text.secondary">Role</Typography>
                        <Typography variant="body1" sx={{ textTransform: 'capitalize' }}>{user?.role ?? 'unknown'}</Typography>
                    </Box>
                </Card>

                <Card title="Saved Preferences By View">
                    {groupedSummaries.length === 0 ? (
                        <Typography variant="body2" color="text.secondary">
                            No saved preferences yet. Changes made in module views will appear here.
                        </Typography>
                    ) : (
                        <Box component="ul" sx={{ listStyle: 'none', m: 0, p: 0, display: 'grid', gap: 1.25 }}>
                            {groupedSummaries.map(([view, viewSummaries]) => (
                                <Box
                                    key={view}
                                    component="li"
                                    sx={{ border: '1px solid', borderColor: 'divider', borderRadius: 1.5, p: 1.5 }}
                                >
                                    <Typography variant="subtitle2" sx={{ mb: 0.5, textTransform: 'capitalize' }}>
                                        {view}
                                    </Typography>
                                    <Box component="ul" sx={{ listStyle: 'none', m: 0, p: 0, display: 'grid', gap: 0.5 }}>
                                        {viewSummaries.map((summary) => (
                                            <Box key={summary.namespace} component="li" sx={{ display: 'flex', justifyContent: 'space-between', gap: 1 }}>
                                                <Typography variant="caption" color="text.secondary">{summary.namespace}</Typography>
                                                <Typography variant="caption" fontWeight={600}>
                                                    {summary.recordCount === null ? 'Saved' : `${summary.recordCount} records`}
                                                </Typography>
                                            </Box>
                                        ))}
                                    </Box>
                                </Box>
                            ))}
                        </Box>
                    )}
                </Card>
            </Box>

            <UserPreferencesPanel
                open={preferencesOpen}
                onClose={() => setPreferencesOpen(false)}
            />
        </section>
    );
};

export default UserProfile;
